processor InlineSine [[ main ]]
{
    output stream float outL, outR;

    input event float frequencyHz [[ name: "Frequency", min: 20.0, max: 2000.0, init: 440.0 ]];
    input event float level [[ name: "Level", min: 0.0, max: 0.5, init: 0.15 ]];

    event frequencyHz (float value) { frequency = value; }
    event level (float value)       { gain = value; }

    void main()
    {
        loop
        {
            let sample = gain * sin (phase);
            outL <- sample;
            outR <- sample;

            phase = addModulo2Pi (phase, float (frequency * processor.period * twoPi));
            advance();
        }
    }

    float frequency = 440.0f;
    float gain = 0.15f;
    float phase = 0.0f;
}
